import React, { useState, useEffect } from 'react';
import "./navbar.css";
import MenuVertical from './menuvertical/menu-vertical.js'

function Navbar() {
    const [MenuVisible, setMenuVisible] = useState(false);

    useEffect(() => {
        const menuvertical = document.querySelector(".menu-vertical");
        if (MenuVisible) {
            menuvertical.style.opacity = "1";
        } else {
            menuvertical.style.opacity = "0";
        }

        return () => {
            if (menuvertical) {
                menuvertical.style.opacity = "0";
            }
        };
    }, [MenuVisible]);




    return (
        <div className="container">
            <nav className="nav">
                <ul className="nav-list">
                    <a href="index.html"><img src="LOGO-N.png" alt='Logo'/></a>
                    <li className="nav-item"><a href="index.html">Inicio</a></li>

                    <li className="nav-item">
                        <a href="productos.html" 
                        onMouseEnter={() => setMenuVisible(true)}
                        onMouseLeave={() => setMenuVisible(false)}>Productos</a>
                        <MenuVertical/>
                    </li>
                    <li className="nav-item"><a href="contacto.html">Contacto</a></li>
                </ul>
            </nav>
        </div>
    );
};

export default Navbar;
